import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjDataGrid } from "./OjDataGrid";
export { OjDataGrid };

/**
 * Create an instance of [[OjDataGrid]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojDataGrid(driver, By.id('my-oj-data-grid'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojDataGrid(driver: DriverLike, by: By): Promise<OjDataGrid> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjDataGrid
  if (!(webEl instanceof OjDataGrid)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-data-grid>`);
  }
  return webEl;
}

register("oj-data-grid", OjDataGrid);
